'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import { AlertCircle, Loader2, Save } from 'lucide-react';
import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Button } from '@/components/ui/button';
import { Field, FieldError, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Input } from '@/components/ui/input';
import type { CreateDriverPayload } from '../types/driver.types';
import {
  createDriverSchema,
  type CreateDriverFormValues,
  type CreateDriverSubmitValues,
} from '../schemas/driver.schema';

interface CreateDriverFormProps {
  isSubmitting: boolean;
  errorMessage?: string | null;
  onSubmit: (payload: CreateDriverPayload) => void;
  onCancel: () => void;
}

export function CreateDriverForm({
  isSubmitting,
  errorMessage,
  onSubmit,
  onCancel,
}: CreateDriverFormProps) {
  const form = useForm<CreateDriverFormValues>({
    resolver: zodResolver(createDriverSchema),
    defaultValues: {
      fullName: '',
      phone: '',
      nationalId: '',
      licenseNumber: '',
      licenseExpiry: '',
      status: 'ACTIVE',
      notes: '',
    },
  });

  const errors = form.formState.errors;

  const submit = form.handleSubmit((values) => {
    const parsed = createDriverSchema.parse(values) as CreateDriverSubmitValues;
    onSubmit({
      fullName: parsed.fullName,
      phone: parsed.phone,
      nationalId: parsed.nationalId,
      licenseNumber: parsed.licenseNumber,
      licenseExpiry: parsed.licenseExpiry,
      status: parsed.status,
      notes: parsed.notes,
    });
  });

  return (
    <form onSubmit={submit} className="space-y-6">
      <FieldGroup className="grid gap-5 lg:grid-cols-2">
        <Field data-invalid={!!errors.fullName}>
          <FieldLabel htmlFor="fullName">Full name</FieldLabel>
          <Input
            id="fullName"
            placeholder="Ahmed Mohamed"
            disabled={isSubmitting}
            aria-invalid={!!errors.fullName}
            {...form.register('fullName')}
          />
          <FieldError errors={[errors.fullName]} />
        </Field>

        <Field data-invalid={!!errors.phone}>
          <FieldLabel htmlFor="phone">Phone</FieldLabel>
          <Input
            id="phone"
            placeholder="+20 100 123 4567"
            disabled={isSubmitting}
            aria-invalid={!!errors.phone}
            {...form.register('phone')}
          />
          <FieldError errors={[errors.phone]} />
        </Field>

        <Field data-invalid={!!errors.nationalId}>
          <FieldLabel htmlFor="nationalId">National ID</FieldLabel>
          <Input
            id="nationalId"
            placeholder="12345678901234"
            disabled={isSubmitting}
            aria-invalid={!!errors.nationalId}
            {...form.register('nationalId')}
          />
          <FieldError errors={[errors.nationalId]} />
        </Field>

        <Field data-invalid={!!errors.licenseNumber}>
          <FieldLabel htmlFor="licenseNumber">License number</FieldLabel>
          <Input
            id="licenseNumber"
            placeholder="EG-DL-2024-001"
            disabled={isSubmitting}
            aria-invalid={!!errors.licenseNumber}
            {...form.register('licenseNumber')}
          />
          <FieldError errors={[errors.licenseNumber]} />
        </Field>

        <Field data-invalid={!!errors.licenseExpiry}>
          <FieldLabel htmlFor="licenseExpiry">License expiry</FieldLabel>
          <Input
            id="licenseExpiry"
            type="date"
            disabled={isSubmitting}
            aria-invalid={!!errors.licenseExpiry}
            {...form.register('licenseExpiry')}
          />
          <FieldError errors={[errors.licenseExpiry]} />
        </Field>

        <Field data-invalid={!!errors.status}>
          <FieldLabel htmlFor="status">Status</FieldLabel>
          <select
            id="status"
            disabled={isSubmitting}
            className="h-8 rounded-lg border border-input bg-background px-2.5 text-sm text-foreground outline-none transition-colors focus:border-ring focus:ring-3 focus:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50"
            aria-invalid={!!errors.status}
            {...form.register('status')}
          >
            <option value="ACTIVE">Active</option>
            <option value="IN_TRIP">In trip</option>
            <option value="INACTIVE">Inactive</option>
            <option value="SUSPENDED">Suspended</option>
          </select>
          <FieldError errors={[errors.status]} />
        </Field>
      </FieldGroup>

      <Field data-invalid={!!errors.notes}>
        <FieldLabel htmlFor="notes">Notes</FieldLabel>
        <textarea
          id="notes"
          rows={4}
          disabled={isSubmitting}
          placeholder="Additional information"
          className="w-full rounded-lg border border-input bg-transparent px-2.5 py-2 text-sm outline-none transition-colors placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50 dark:bg-input/30"
          aria-invalid={!!errors.notes}
          {...form.register('notes')}
        />
        <FieldError errors={[errors.notes]} />
      </Field>

      {errorMessage ? (
        <Alert variant="destructive">
          <AlertCircle className="size-4" />
          <AlertDescription>{errorMessage}</AlertDescription>
        </Alert>
      ) : null}

      <div className="flex flex-col-reverse gap-2 border-t pt-4 sm:flex-row sm:justify-end">
        <Button type="button" variant="outline" onClick={onCancel} disabled={isSubmitting}>
          Cancel
        </Button>
        <Button type="submit" disabled={isSubmitting}>
          {isSubmitting ? <Loader2 className="size-4 animate-spin" /> : <Save className="size-4" />}
          Create driver
        </Button>
      </div>
    </form>
  );
}
