'use client';

import type { ColumnDef } from '@tanstack/react-table';
import { StatusBadge } from '@/components/shared';
import type { Driver } from '../types/driver.types';
import { DriverActionsMenu } from './driver-actions-menu';

function formatDate(value: string) {
  return new Intl.DateTimeFormat('en', {
    year: 'numeric',
    month: 'short',
    day: '2-digit',
  }).format(new Date(value));
}

export const driverColumns: ColumnDef<Driver, unknown>[] = [
  {
    accessorKey: 'fullName',
    header: 'Name',
    cell: ({ row }) => <span className="font-medium">{row.original.fullName}</span>,
  },
  {
    accessorKey: 'phone',
    header: 'Phone',
  },
  {
    accessorKey: 'nationalId',
    header: 'National ID',
  },
  {
    accessorKey: 'licenseNumber',
    header: 'License',
  },
  {
    accessorKey: 'licenseExpiry',
    header: 'License expiry',
    cell: ({ row }) => formatDate(row.original.licenseExpiry),
  },
  {
    accessorKey: 'status',
    header: 'Status',
    cell: ({ row }) => <StatusBadge status={row.original.status} domain="driver" />,
  },
  {
    accessorKey: 'createdAt',
    header: 'Created',
    cell: ({ row }) => formatDate(row.original.createdAt),
  },
  {
    id: 'actions',
    header: '',
    cell: () => <DriverActionsMenu />,
  },
];
