'use client';

import { ShieldAlert } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { EmptyState, PageHeader } from '@/components/shared';
import { Card, CardContent } from '@/components/ui/card';
import { useToast } from '@/components/ui/toast';
import { PERMISSIONS } from '@/constants/permissions';
import { ROUTES } from '@/constants/routes';
import { usePermissions } from '@/features/auth/hooks/use-permissions';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { useCreateDriver } from '../hooks/use-drivers';
import type { CreateDriverPayload } from '../types/driver.types';
import { CreateDriverForm } from '../forms/create-driver-form';

export function CreateDriverPage() {
  const router = useRouter();
  const { toast } = useToast();
  const { hasPermission } = usePermissions();
  const mutation = useCreateDriver();
  const canCreate = hasPermission(PERMISSIONS.CREATE_DRIVER);

  function handleSubmit(payload: CreateDriverPayload) {
    mutation.mutate(payload, {
      onSuccess: (driver) => {
        toast({
          title: 'Driver created',
          description: `${driver.fullName} has been added to the fleet.`,
          variant: 'success',
        });
        router.push(ROUTES.drivers);
        router.refresh();
      },
      onError: (error) => {
        toast({
          title: 'Driver was not created',
          description: getApiErrorMessage(error, 'Check the form and try again.'),
          variant: 'error',
        });
      },
    });
  }

  if (!canCreate) {
    return (
      <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
        <PageHeader
          title="Create driver"
          description="Add a new driver profile to the transport management system."
        />
        <EmptyState
          icon={ShieldAlert}
          title="Permission required"
          description="You do not have permission to create drivers."
        />
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title="Create driver"
        description="Add a new driver with license and contact information."
      />

      <Card>
        <CardContent>
          <CreateDriverForm
            isSubmitting={mutation.isPending}
            errorMessage={
              mutation.error
                ? getApiErrorMessage(mutation.error, 'Unable to create driver.')
                : null
            }
            onSubmit={handleSubmit}
            onCancel={() => router.push(ROUTES.drivers)}
          />
        </CardContent>
      </Card>
    </div>
  );
}
