import { z } from 'zod';

export const driverStatusSchema = z.enum(['ACTIVE', 'IN_TRIP', 'INACTIVE', 'SUSPENDED']);

const optionalTrimmedText = z
  .string()
  .trim()
  .optional()
  .transform((value) => (value ? value : undefined));

export const createDriverSchema = z.object({
  fullName: z.string().trim().min(1, 'Full name is required').max(255),
  phone: z.string().trim().min(1, 'Phone number is required').max(50),
  nationalId: z.string().trim().min(1, 'National ID is required').max(100),
  licenseNumber: z.string().trim().min(1, 'License number is required').max(100),
  licenseExpiry: z.string().min(1, 'License expiry date is required'),
  status: driverStatusSchema.default('ACTIVE'),
  notes: optionalTrimmedText,
});

export const updateDriverSchema = z.object({
  fullName: z.string().trim().min(1, 'Full name is required').max(255).optional(),
  phone: z.string().trim().min(1, 'Phone number is required').max(50).optional(),
  nationalId: z.string().trim().min(1, 'National ID is required').max(100).optional(),
  licenseNumber: z.string().trim().min(1, 'License number is required').max(100).optional(),
  licenseExpiry: z.string().min(1, 'License expiry date is required').optional(),
  status: driverStatusSchema.optional(),
  notes: optionalTrimmedText,
});

export type CreateDriverFormValues = z.input<typeof createDriverSchema>;
export type CreateDriverSubmitValues = z.output<typeof createDriverSchema>;

export type UpdateDriverFormValues = z.input<typeof updateDriverSchema>;
export type UpdateDriverSubmitValues = z.output<typeof updateDriverSchema>;
