'use client';

import { AlertCircle, Plus } from 'lucide-react';
import { useMemo, useState } from 'react';
import { DataTableShell, EmptyState, LoadingSkeleton, PageHeader } from '@/components/shared';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { PERMISSIONS } from '@/constants/permissions';
import { ROUTES } from '@/constants/routes';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { usePermissions } from '@/features/auth/hooks/use-permissions';
import Link from 'next/link';
import { useDrivers } from '../hooks/use-drivers';
import type { DriverStatus } from '../types/driver.types';
import { DriverFilters } from './driver-filters';
import { driverColumns } from './driver-table-columns';
import { DriversPagination } from './drivers-pagination';

const DEFAULT_LIMIT = 20;

export function DriversListPage() {
  const { hasPermission } = usePermissions();
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState<DriverStatus | undefined>();
  const [availableOnly, setAvailableOnly] = useState(false);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(DEFAULT_LIMIT);

  const queryParams = useMemo(
    () => ({
      page,
      limit,
      search: search.trim() || undefined,
      status,
      availableOnly: availableOnly || undefined,
    }),
    [availableOnly, limit, page, search, status],
  );

  const driversQuery = useDrivers(queryParams);
  const drivers = driversQuery.data?.items ?? [];
  const meta = driversQuery.data?.meta ?? {
    page,
    limit,
    total: 0,
    totalPages: 0,
  };

  const canCreateDriver = hasPermission(PERMISSIONS.CREATE_DRIVER);
  const hasActiveFilters = Boolean(search || status || availableOnly);
  const errorMessage = driversQuery.error
    ? getApiErrorMessage(driversQuery.error, 'Unable to load drivers.')
    : null;

  function resetPageAndRun(action: () => void) {
    setPage(1);
    action();
  }

  function resetFilters() {
    setSearch('');
    setStatus(undefined);
    setAvailableOnly(false);
    setPage(1);
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title="Drivers"
        description="Manage driver profiles, license info, and operational availability."
        actions={
          canCreateDriver ? (
            <Button type="button" render={<Link href={ROUTES.driversNew} />}>
              <Plus className="size-4" />
              New driver
            </Button>
          ) : null
        }
      />

      {driversQuery.isLoading ? (
        <LoadingSkeleton variant="table" />
      ) : errorMessage ? (
        <Card>
          <CardContent>
            <EmptyState
              icon={AlertCircle}
              title="Unable to load drivers"
              description={errorMessage}
              actionLabel="Retry"
              onAction={() => void driversQuery.refetch()}
              className="border-0 bg-transparent"
            />
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="space-y-4">
            <DataTableShell
              columns={driverColumns}
              data={drivers}
              isLoading={driversQuery.isFetching && !driversQuery.isLoading}
              searchPlaceholder="Search name, phone, national ID…"
              searchValue={search}
              onSearchChange={(value) => resetPageAndRun(() => setSearch(value))}
              emptyTitle={hasActiveFilters ? 'No drivers match these filters' : 'No drivers yet'}
              emptyDescription={
                hasActiveFilters
                  ? 'Reset filters or try a different search term.'
                  : 'Drivers created from the backend API will appear here.'
              }
              footerLabel={null}
              toolbar={
                <DriverFilters
                  status={status}
                  availableOnly={availableOnly}
                  onStatusChange={(value) => resetPageAndRun(() => setStatus(value))}
                  onAvailableOnlyChange={(value) =>
                    resetPageAndRun(() => {
                      setAvailableOnly(value);
                      if (value) setStatus(undefined);
                    })
                  }
                  onReset={resetFilters}
                />
              }
            />

            <DriversPagination
              page={meta.page}
              limit={meta.limit}
              total={meta.total}
              totalPages={meta.totalPages}
              onPageChange={setPage}
              onLimitChange={(value) => {
                setLimit(value);
                setPage(1);
              }}
            />
          </CardContent>
        </Card>
      )}
    </div>
  );
}
