'use client';

import { AlertCircle, ShieldAlert } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { EmptyState, LoadingSkeleton, PageHeader } from '@/components/shared';
import { Card, CardContent } from '@/components/ui/card';
import { useToast } from '@/components/ui/toast';
import { PERMISSIONS } from '@/constants/permissions';
import { ROUTES } from '@/constants/routes';
import { usePermissions } from '@/features/auth/hooks/use-permissions';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { useDriver, useUpdateDriver } from '../hooks/use-drivers';
import type { UpdateDriverPayload } from '../types/driver.types';
import { UpdateDriverForm } from '../forms/update-driver-form';

interface EditDriverPageProps {
  driverId: string;
}

export function EditDriverPage({ driverId }: EditDriverPageProps) {
  const router = useRouter();
  const { toast } = useToast();
  const { hasPermission } = usePermissions();
  const { data: driver, isLoading, error } = useDriver(driverId);
  const mutation = useUpdateDriver(driverId);
  const canUpdate = hasPermission(PERMISSIONS.UPDATE_DRIVER);

  function handleSubmit(payload: UpdateDriverPayload) {
    mutation.mutate(payload, {
      onSuccess: (updated) => {
        toast({
          title: 'Driver updated',
          description: `${updated.fullName} has been updated.`,
          variant: 'success',
        });
        router.push(ROUTES.drivers);
        router.refresh();
      },
      onError: (err) => {
        toast({
          title: 'Driver was not updated',
          description: getApiErrorMessage(err, 'Check the form and try again.'),
          variant: 'error',
        });
      },
    });
  }

  if (!canUpdate) {
    return (
      <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
        <PageHeader title="Edit driver" description="Update driver profile information." />
        <EmptyState
          icon={ShieldAlert}
          title="Permission required"
          description="You do not have permission to update drivers."
        />
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
        <PageHeader title="Edit driver" description="Loading driver information…" />
        <LoadingSkeleton variant="form" />
      </div>
    );
  }

  if (error || !driver) {
    return (
      <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
        <PageHeader title="Edit driver" description="Driver could not be loaded." />
        <EmptyState
          icon={AlertCircle}
          title="Unable to load driver"
          description={getApiErrorMessage(error, 'Driver not found.')}
          actionLabel="Go back"
          onAction={() => router.push(ROUTES.drivers)}
        />
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title={`Edit ${driver.fullName}`}
        description="Update driver profile, license, or contact information."
      />

      <Card>
        <CardContent>
          <UpdateDriverForm
            driver={driver}
            isSubmitting={mutation.isPending}
            errorMessage={
              mutation.error
                ? getApiErrorMessage(mutation.error, 'Unable to update driver.')
                : null
            }
            onSubmit={handleSubmit}
            onCancel={() => router.push(ROUTES.drivers)}
          />
        </CardContent>
      </Card>
    </div>
  );
}
